import { Link } from 'react-router-dom';

class Evalulation extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
          results: []
        };
    }

        componentDidMount() {
            // get all entities - GET
            fetch(`http://localhost:9000/amioncall`, {
                "method": "GET"
              })
